parameters.jsonBody:
={
  "username": "Goldman Sachs Gold Desk",
  "avatar_url": "https://i.imgur.com/8QzD2N2.png",
  "embeds": [
    {
      "title": "🚨 LIVE XAUUSD INSTITUTIONAL ANALYSIS REPORT",
      "color": 16766720,
      "description": "Goldman Sachs & JP Morgan Institutional Gold Trader Daily Summary Report.",
      "fields": [
        {
          "name": "Final Verdict Recommendation",
          "value": "**" + $json.report.primary_objective.verdict + "**",
          "inline": true
        },
        {
          "name": "Market Bias Direction",
          "value": "**" + $json.report.primary_objective.bias + "**",
          "inline": true
        },
        {
          "name": "Success Probability",
          "value": "**" + $json.report.primary_objective.probability + "**",
          "inline": true
        },
        {
          "name": "Entry Trigger Level",
          "value": "**$" + $json.report.primary_objective.entry + "**",
          "inline": true
        },
        {
          "name": "Stop Loss Price",
          "value": "**$" + $json.report.primary_objective.sl + "**",
          "inline": true
        },
        {
          "name": "Risk:Reward Ratio",
          "value": "**" + $json.report.primary_objective.reward_ratio + "**",
          "inline": true
        },
        {
          "name": "Gold Current Price",
          "value": "**$" + $json.report.part_6_fundamental_analysis.yields_dxy.split(' ')[0] + "**",
          "inline": false
        },
        {
          "name": "Invalidation Level",
          "value": "**$" + $json.report.part_13_invalidation.price + "**",
          "inline": true
        },
        {
          "name": "Key Institutional Focus",
          "value": $json.report.part_14_final_verdict.summary,
          "inline": false
        }
      ],
      "footer": {
        "text": "Generated at: " + $json.report.timestamp
      }
    }
  ]
}
